INSERT INTO `tests` (`id`, `subject_id`, `difficulty_id`, `title`, `description`, `time_limit`, `points_for_completion`, `theory`, `is_active`, `created_at`, `updated_at`) VALUES
(16, 1, 1, 'Сложение и вычитание до 10', NULL, NULL, 10, '<h3>Сложение и вычитание</h3><p>Сложение – это объединение чисел. Например, 2 + 3 = 5. Вычитание – это нахождение разности. Например, 5 - 2 = 3.</p>', 1, '2026-06-13 12:02:13', '2026-06-13 12:02:13'),
(2, 1, 1, 'Математика – 1 класс', NULL, NULL, 10, NULL, 1, '2026-06-11 14:19:16', '2026-06-11 14:19:16'),
(3, 1, 2, 'Математика – 2 класс', NULL, NULL, 10, NULL, 1, '2026-06-11 14:19:16', '2026-06-11 14:19:16'),
(4, 1, 3, 'Математика – 3 класс', NULL, NULL, 10, NULL, 1, '2026-06-11 14:19:16', '2026-06-11 14:19:16'),
(5, 1, 4, 'Математика – 4 класс', NULL, NULL, 10, NULL, 1, '2026-06-11 14:19:16', '2026-06-11 14:19:16'),
(6, 2, 1, 'Русский язык – 1 класс', NULL, NULL, 10, NULL, 1, '2026-06-11 14:19:16', '2026-06-11 14:19:16'),
(7, 2, 2, 'Русский язык – 2 класс', NULL, NULL, 10, NULL, 1, '2026-06-11 14:19:16', '2026-06-11 14:19:16'),
(8, 2, 3, 'Русский язык – 3 класс', NULL, NULL, 10, NULL, 1, '2026-06-11 14:19:16', '2026-06-11 14:19:16'),
(9, 2, 4, 'Русский язык – 4 класс', NULL, NULL, 10, NULL, 1, '2026-06-11 14:19:16', '2026-06-11 14:19:16'),
(10, 3, 1, 'Окружающий мир – 1 класс', NULL, NULL, 10, NULL, 1, '2026-06-11 14:19:16', '2026-06-11 14:19:16'),
(11, 3, 2, 'Окружающий мир – 2 класс', NULL, NULL, 10, NULL, 1, '2026-06-11 14:19:16', '2026-06-11 14:19:16'),
(12, 3, 3, 'Окружающий мир – 3 класс', NULL, NULL, 10, NULL, 1, '2026-06-11 14:19:16', '2026-06-11 14:19:16'),
(13, 3, 4, 'Окружающий мир – 4 класс', NULL, NULL, 10, NULL, 1, '2026-06-11 14:19:16', '2026-06-11 14:19:16'),
(17, 1, 1, 'Сравнение чисел', NULL, NULL, 10, '<h3>Сравнение чисел</h3><p>Знак \"больше\" (>), \"меньше\" (<), \"равно\" (=). Например, 5 > 3, 2 < 4.</p>', 1, '2026-06-13 12:02:13', '2026-06-13 12:02:13'),
(18, 1, 2, 'Умножение и деление на 2', NULL, NULL, 10, '<h3>Умножение и деление на 2</h3><p>Умножение – это сложение одинаковых слагаемых. Например, 2 × 3 = 6. Деление – нахождение количества одинаковых частей.</p>', 1, '2026-06-13 12:02:13', '2026-06-13 12:02:13'),
(19, 1, 2, 'Таблица умножения на 3', NULL, NULL, 10, '<h3>Таблица умножения на 3</h3><p>3 × 1 = 3, 3 × 2 = 6, 3 × 3 = 9, 3 × 4 = 12, 3 × 5 = 15.</p>', 1, '2026-06-13 12:02:13', '2026-06-13 12:02:13'),
(20, 1, 3, 'Внетабличное умножение и деление', NULL, NULL, 10, '<h3>Внетабличное умножение и деление</h3><p>Например, 20 × 3 = 60, 60 ÷ 3 = 20.</p>', 1, '2026-06-13 12:02:14', '2026-06-13 12:02:14'),
(21, 1, 3, 'Площадь и периметр', NULL, NULL, 10, '<h3>Площадь и периметр</h3><p>Периметр – сумма всех сторон. Площадь – произведение длины на ширину.</p>', 1, '2026-06-13 12:02:14', '2026-06-13 12:02:14'),
(22, 1, 4, 'Дроби', NULL, NULL, 10, '<h3>Дроби</h3><p>Дробь показывает часть целого. Например, 1/2 – половина.</p>', 1, '2026-06-13 12:02:14', '2026-06-13 12:02:14'),
(23, 1, 4, 'Уравнения', NULL, NULL, 10, '<h3>Уравнения</h3><p>Уравнение – это равенство, содержащее неизвестное число. Например, x + 5 = 10, x = 5.</p>', 1, '2026-06-13 12:02:14', '2026-06-13 12:02:14'),
(24, 2, 1, 'Алфавит и звуки', NULL, NULL, 10, '<h3>Русский алфавит</h3><p>33 буквы. Гласные: А, О, У, Ы, Э, Я, Ё, Ю, И, Е. Согласные: остальные.</p>', 1, '2026-06-13 12:02:14', '2026-06-13 12:02:14'),
(25, 2, 1, 'Слоги и ударение', NULL, NULL, 10, '<h3>Слоги и ударение</h3><p>Слово делится на слоги. Ударение – выделение голосом одного слога.</p>', 1, '2026-06-13 12:02:14', '2026-06-13 12:02:14'),
(26, 2, 2, 'Части речи', NULL, NULL, 10, '<h3>Части речи</h3><p>Имя существительное (кто? что?), имя прилагательное (какой?), глагол (что делает?).</p>', 1, '2026-06-13 12:02:14', '2026-06-13 12:02:14'),
(27, 2, 2, 'Правописание жи-ши, ча-ща, чу-щу', NULL, NULL, 10, '<h3>Правила жи-ши, ча-ща, чу-щу</h3><p>Жи-ши пиши с буквой И. Ча-ща пиши с буквой А. Чу-щу пиши с буквой У.</p>', 1, '2026-06-13 12:02:14', '2026-06-13 12:02:14'),
(28, 2, 3, 'Падежи имён существительных', NULL, NULL, 10, '<h3>Падежи</h3><p>Именительный (кто? что?), Родительный (кого? чего?), Дательный (кому? чему?), Винительный (кого? что?), Творительный (кем? чем?), Предложный (о ком? о чём?).</p>', 1, '2026-06-13 12:02:14', '2026-06-13 12:02:14'),
(29, 2, 3, 'Род имён существительных', NULL, NULL, 10, '<h3>Род имён существительных</h3><p>Мужской (он, мой), женский (она, моя), средний (оно, моё).</p>', 1, '2026-06-13 12:02:14', '2026-06-13 12:02:14'),
(30, 2, 4, 'Спряжение глаголов', NULL, NULL, 10, '<h3>Спряжение глаголов</h3><p>I спряжение: окончания -ешь, -ет, -ем, -ете, -ут (-ют). II спряжение: -ишь, -ит, -им, -ите, -ат (-ят).</p>', 1, '2026-06-13 12:02:14', '2026-06-13 12:02:14'),
(31, 2, 4, 'Однородные члены предложения', NULL, NULL, 10, '<h3>Однородные члены</h3><p>Отвечают на один вопрос, относятся к одному слову, перечисляются.</p>', 1, '2026-06-13 12:02:14', '2026-06-13 12:02:14'),
(32, 3, 1, 'Живая и неживая природа', NULL, NULL, 10, '<h3>Живая и неживая природа</h3><p>Живая природа: растения, животные, грибы, бактерии. Неживая: камни, вода, воздух.</p>', 1, '2026-06-13 12:02:14', '2026-06-13 12:02:14'),
(33, 3, 1, 'Времена года', NULL, NULL, 10, '<h3>Времена года</h3><p>Зима, весна, лето, осень. Каждый сезон имеет свои особенности.</p>', 1, '2026-06-13 12:02:14', '2026-06-13 12:02:14'),
(34, 3, 2, 'Растения и животные леса', NULL, NULL, 10, '<h3>Лес – экосистема</h3><p>В лесу растут деревья, кустарники, травы, живут звери, птицы, насекомые.</p>', 1, '2026-06-13 12:02:14', '2026-06-13 12:02:14'),
(35, 3, 2, 'Вода и её свойства', NULL, NULL, 10, '<h3>Вода</h3><p>Вода бывает в трёх состояниях: жидкое, твёрдое (лёд), газообразное (пар). Не имеет вкуса, цвета, запаха.</p>', 1, '2026-06-13 12:02:14', '2026-06-13 12:02:14'),
(36, 3, 3, 'Организм человека', NULL, NULL, 10, '<h3>Тело человека</h3><p>Скелет, мышцы, сердце, лёгкие, желудок. Здоровый образ жизни.</p>', 1, '2026-06-13 12:02:14', '2026-06-13 12:02:14'),
(37, 3, 3, 'Планета Земля', NULL, NULL, 10, '<h3>Земля – планета</h3><p>Земля вращается вокруг Солнца и вокруг своей оси. Смена дня и ночи, времён года.</p>', 1, '2026-06-13 12:02:14', '2026-06-13 12:02:14'),
(38, 3, 4, 'История России (основные события)', NULL, NULL, 10, '<h3>Вехи истории России</h3><p>Киевская Русь, Куликовская битва, правление Петра I, Великая Отечественная война.</p>', 1, '2026-06-13 12:02:14', '2026-06-13 12:02:14'),
(39, 3, 4, 'Береги природу!', NULL, NULL, 10, '<h3>Охрана природы</h3><p>Красная книга, заповедники, экологические проблемы. Как помочь природе.</p>', 1, '2026-06-13 12:02:14', '2026-06-13 12:02:14');
